    pub hours: u32,
    pub billable: bool,
}

pub fn build_report(entries: &[Entry]) -> String {
    let mut totals: BTreeMap<&str, (u32, u32)> = BTreeMap::new();

    for entry in entries {
        if entry.hours == 0 {
            continue;
        }
        let bucket = totals.entry(entry.team).or_insert((0, 0));
        bucket.0 += entry.hours;
        if entry.billable {
            bucket.1 += entry.hours;
