    "src/lib.rs": "#[derive(Debug, Clone, Copy, PartialEq, Eq)]
pub struct Booking {
    pub start: u32,
    pub end: u32,
}

impl Booking {
    pub fn new(start: u32, end: u32) -> Option<Self> {
        if start >= end {
            None
        } else {
            Some(Self { start, end })
        }
    }

    pub fn overlaps(&self, other: &Booking) -> bool {
        self.start <= other.end && other.start <= self.end
    }
}

pub fn can_book(existing: &[Booking], candidate: Booking) -> bool {
    existing.iter().all(|slot| !slot.overlaps(&candidate))
}

pub fn first_conflict(existing: &[Booking], candidate: Booking) -> Option<Booking> {
    existing.iter().copied().find(|slot| slot.overlaps(&candidate))
}

pub fn insert_booking(existing: &mut Vec<Booking>, candidate: Booking) -> bool {
    if !can_book(existing, candidate) {
        return false;
    }
    existing.push(candidate);
    existing.sort_by_key(|b| b.start);
    true
}

