    "src/main.rs": "use std::collections::BTreeMap;

#[derive(Clone, Copy)]
enum Status {
    Todo,
    InProgress,
    Blocked,
    Closed,
}

impl Status {
    fn as_str(self) -> &'static str {
        match self {
            Status::Todo => "Todo",
            Status::InProgress => "InProgress",
            Status::Blocked => "Blocked",
            Status::Closed => "Closed",
        }
    }
}

fn apply(status: Status, event: &str) -> Status {
    match event {
        "start" => Status::InProgress,
        "block" => Status::Blocked,
        "resume" => Status::Todo,
        "close" => status,
        _ => status,
    }
}

fn main() {
    let events = [
        ("T1", "start"),
        ("T1", "close"),
        ("T2", "start"),
        ("T2", "block"),
        ("T3", "start"),
    ];

    let mut states: BTreeMap<&str, Status> = BTreeMap::new();

    for (ticket, event) in events {
        let current = states.get(ticket).copied().unwrap_or(Status::Todo);
        let next = apply(current, event);
        states.insert(ticket, next);
    }

    for (ticket, status) in states {
        println!("{}={}", ticket, status.as_str());
    }
}
