DELETE /health => method_not_allowed
TOTAL ok=3 client=2 server=1",
  "files": {
    "Cargo.toml": "[package]
name = "route_action_summary_match_recovery"
version = "0.1.0"
edition = "2021"

[dependencies]
",
    "src/main.rs": "enum Method {
    Get,
    Post,
    Delete,
}

enum Route {
    Health,
    Items,
    Item(u32),
    Admin,
}

enum Outcome {
    Ok(&'static str),
    Client(&'static str),
    Server(&'static str),
}

fn dispatch(method: Method, route: Route) -> Outcome {
    match route {
        Route::Health => Outcome::Ok("served"),
        Route::Items => match method {
            Method::Get => Outcome::Ok("served"),
            Method::Post => Outcome::Ok("created"),
            Method::Delete => Outcome::Client("method_not_allowed"),
        },
        Route::Item(_) => match method {
            Method::Get => Outcome::Ok("served"),
            Method::Post => Outcome::Ok("created"),
            Method::Delete => Outcome::Ok("deleted"),
        },
        Route::Admin => Outcome::Server("forbidden"),
    }
}

fn method_name(method: &Method) -> &'static str {
    match method {
        Method::Get => "GET",
        Method::Post => "POST",
        Method::Delete => "DELETE",
    }
}

fn route_name(route: &Route) -> String {
    match route {
        Route::Health => "/health".to_string(),
        Route::Items => "/items".to_string(),
        Route::Item(id) => format!("/items/{id}"),
        Route::Admin => "/admin".to_string(),
    }
}

fn outcome_text(outcome: &Outcome) -> &'static str {
    match outcome {
        Outcome::Ok(msg) | Outcome::Client(msg) | Outcome::Server(msg) => msg,
    }
}

fn bucket(outcome: &Outcome) -> &'static str {
    match outcome {
        Outcome::Ok(_) => "ok",
        Outcome::Client(_) => "client",
        Outcome::Server(_) => "server",
    }
}

fn main() {
    let requests = vec![
        (Method::Get, Route::Health),
        (Method::Get, Route::Admin),
        (Method::Post, Route::Items),
        (Method::Post, Route::Item(42)),
        (Method::Delete, Route::Item(42)),
        (Method::Delete, Route::Health),
    ];

    let mut ok = 0;
    let mut client = 0;
    let mut server = 0;

    for (method, route) in requests {
        let outcome = dispatch(method, route);
        match bucket(&outcome) {
            "ok" => ok += 1,
            "client" => client += 1,
            _ => server += 1,
        }
        println!(
            "{} {} => {}",
            method_name(&method),
            route_name(&route),
            outcome_text(&outcome)
        );
    }

    println!("TOTAL ok={ok} client={client} server={server}");
}
