",
    "src/main.rs": "fn parse_hhmm(s: &str) -> u32 {
    let (h, m) = s.split_once(':').unwrap();
    h.parse::<u32>().unwrap() * 60 + m.parse::<u32>().unwrap()
}

fn fmt_hhmm(mins: u32) -> String {
    format!("{:02}:{:02}", mins / 60, mins % 60)
}

#[derive(Clone, Copy)]
struct Booking {
    start: u32,
    end: u32,
}

impl Booking {
    fn label(&self) -> String {
        format!("{}-{}", fmt_hhmm(self.start), fmt_hhmm(self.end))
    }
}

fn conflicts(a: Booking, b: Booking) -> bool {
    (a.start <= b.end) && (b.start <= a.end)
}

fn can_book(existing: &[Booking], candidate: Booking) -> bool {
    if candidate.start >= candidate.end {
        return false;
    }
    !existing.iter().any(|&b| b.start <= candidate.start && candidate.end <= b.end)
}

fn main() {
    let requests = [
        Booking { start: parse_hhmm("09:00"), end: parse_hhmm("10:00") },
        Booking { start: parse_hhmm("10:00"), end: parse_hhmm("11:00") },
        Booking { start: parse_hhmm("09:30"), end: parse_hhmm("09:45") },
        Booking { start: parse_hhmm("11:00"), end: parse_hhmm("12:00") },
        Booking { start: parse_hhmm("08:00"), end: parse_hhmm("12:00") },
        Booking { start: parse_hhmm("12:00"), end: parse_hhmm("13:00") },
    ];

    let mut accepted: Vec<Booking> = Vec::new();
    let mut lines: Vec<String> = Vec::new();

    for (idx, req) in requests.iter().copied().enumerate() {
        if can_book(&accepted, req) {
            accepted.push(req);
            accepted.sort_by_key(|b| b.start);
            lines.push(format!(
                "accepted #{} [{}-{})",
                idx + 1,
                fmt_hhmm(req.start),
                fmt_hhmm(req.end)
            ));
        } else {
            lines.push(format!(
                "rejected #{} [{}-{})",
                idx + 1,
                fmt_hhmm(req.start),
                fmt_hhmm(req.end)
            ));
        }
    }

    lines.push("final bookings:".to_string());
    for b in &accepted {
        lines.push(b.label());
    }

    print!("{}", lines.join("\n"));
}
